import React, { useState, useEffect } from 'react';
import { ShoppingCart, MapPin, Box, UserCheck } from 'lucide-react';

const PanelCliente = () => {
  const [ofertas, setOfertas] = useState([]);

  useEffect(() => {
    // Obtenemos los locales para cruzar la información de ubicación
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let todas = [];

    locales.forEach(l => {
      // Cargamos las ofertas específicas de cada sucursal
      const off = JSON.parse(localStorage.getItem(`ofertas-local-${l.id}`) || "[]");
      todas = [...todas, ...off.map(o => ({ 
        ...o, 
        local: l.nombre, 
        zona: l.zona || 'Barrio Norte',
        coords: l.coords 
      }))];
    });

    setTodasOfertas(todas);
  }, []);

  const setTodasOfertas = (data) => {
    setOfertas(data);
  };

  return (
    <div style={{ padding: '30px 5%', background: '#f8fafc', minHeight: '90vh' }}>
      <div style={headerSection}>
        <div>
          <h2 style={{ margin: 0, color: '#1e293b' }}>Panel de Ofertas</h2>
          <p style={{ color: '#64748b', marginTop: '5px' }}>Explora los detalles de cada producto disponible en tu zona.</p>
        </div>
        <div style={statsBadge}>
          {ofertas.length} Ofertas activas
        </div>
      </div>

      <div style={gridEstilo}>
        {ofertas.map(o => {
          const ahorro = Math.round(((o.precioViejo - o.precioNuevo) / o.precioViejo) * 100);
          
          return (
            <div key={o.id} style={cardEstilo}>
              <div style={badgeAhorro}>-{ahorro}%</div>
              
              <div style={imgWrapper}>
                {o.imagen ? (
                  <img src={o.imagen} alt={o.producto} style={imgEstilo} />
                ) : (
                  <div style={noImg}><Box size={40} color="#cbd5e1" /></div>
                )}
              </div>
              
              <div style={{ padding: '20px' }}>
                <h3 style={tituloProd}>{o.producto}</h3>
                
                <div style={preciosContainer}>
                  <span style={pNuevo}>${o.precioNuevo}</span>
                  <span style={pViejo}>${o.precioViejo}</span>
                </div>

                <div style={detalleGrid}>
                  <div style={tagInfo}>
                    <Box size={14} /> 
                    <span>Stock: <strong>{o.stock}</strong></span>
                  </div>
                  <div style={tagInfo}>
                    <UserCheck size={14} /> 
                    <span>Límite: <strong>{o.limitePorCliente}</strong></span>
                  </div>
                </div>

                <div style={divider} />

                <div style={footerCard}>
                  <div style={localInfo}>
                    <MapPin size={14} color="#e67e22" />
                    <span style={localName}>{o.local}</span>
                  </div>
                  <button style={btnReserva}>
                    <ShoppingCart size={16} /> Reservar
                  </button>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

/* --- ESTILOS DE ALTO IMPACTO --- */
const headerSection = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const statsBadge = { background: '#1e293b', color: 'white', padding: '8px 16px', borderRadius: '10px', fontSize: '0.9rem', fontWeight: 'bold' };
const gridEstilo = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '25px' };
const cardEstilo = { background: 'white', borderRadius: '24px', overflow: 'hidden', boxShadow: '0 4px 20px rgba(0,0,0,0.05)', position: 'relative', border: '1px solid #f1f5f9' };
const imgWrapper = { height: '200px', background: '#f8fafc', overflow: 'hidden' };
const imgEstilo = { width: '100%', height: '100%', objectFit: 'cover' };
const noImg = { height: '100%', display: 'flex', justifyContent: 'center', alignItems: 'center' };
const badgeAhorro = { position: 'absolute', top: '15px', right: '15px', background: '#ef4444', color: 'white', padding: '6px 12px', borderRadius: '10px', fontWeight: '900', z_index: 10, fontSize: '0.9rem' };
const tituloProd = { margin: '0 0 10px 0', fontSize: '1.25rem', color: '#1e293b', fontWeight: '700' };
const preciosContainer = { display: 'flex', alignItems: 'baseline', gap: '10px', marginBottom: '18px' };
const pNuevo = { fontSize: '2rem', fontWeight: '900', color: '#1e293b' };
const pViejo = { fontSize: '1.1rem', textDecoration: 'line-through', color: '#94a3b8' };
const detalleGrid = { display: 'flex', gap: '10px', marginBottom: '20px' };
const tagInfo = { flex: 1, fontSize: '0.8rem', color: '#475569', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '6px', background: '#f1f5f9', padding: '8px', borderRadius: '10px' };
const divider = { height: '1px', background: '#f1f5f9', margin: '0 0 15px 0' };
const footerCard = { display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '15px' };
const localInfo = { display: 'flex', alignItems: 'center', gap: '6px', maxWidth: '140px' };
const localName = { fontSize: '0.85rem', color: '#64748b', fontWeight: '600', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' };
const btnReserva = { flex: 1, padding: '12px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', transition: '0.3s' };

export default PanelCliente;
